# -*- coding: utf-8 -*-
"""Falsafa - 10 mavzu konspekt generatori."""
import zipfile, datetime
TOPICS = []
def esc(t): return t.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace('"',"&quot;")
def run(text,bold=False,size=28,font="Times New Roman"):
    rpr='<w:rPr><w:rFonts w:ascii="%s" w:hAnsi="%s" w:cs="%s"/>'%(font,font,font)
    if bold: rpr+='<w:b/><w:bCs/>'
    rpr+='<w:sz w:val="%d"/><w:szCs w:val="%d"/></w:rPr>'%(size,size)
    return '<w:r>%s<w:t xml:space="preserve">%s</w:t></w:r>'%(rpr,esc(text))
def para(text,bold=False,size=28,align="both",indent_first=709,space_after=120,line=360,keep_next=False):
    ppr='<w:pPr>'
    if keep_next: ppr+='<w:keepNext/>'
    ppr+='<w:spacing w:after="%d" w:line="%d" w:lineRule="auto"/>'%(space_after,line)
    if indent_first: ppr+='<w:ind w:firstLine="%d"/>'%indent_first
    ppr+='<w:jc w:val="%s"/></w:pPr>'%align
    return '<w:p>%s%s</w:p>'%(ppr,run(text,bold=bold,size=size))
def page_break(): return '<w:p><w:r><w:br w:type="page"/></w:r></w:p>'
def empty_para(): return '<w:p><w:pPr><w:spacing w:after="0" w:line="360" w:lineRule="auto"/></w:pPr></w:p>'
def build_topic(t,is_first):
    parts=[]
    if not is_first: parts.append(page_break())
    parts.append(para("%d-MAVZU. %s"%(t["num"],t["title"].upper()),bold=True,size=30,align="center",indent_first=0,space_after=180,keep_next=True))
    parts.append(para("Reja:",bold=True,size=28,align="left",indent_first=0,space_after=60,keep_next=True))
    for i,r in enumerate(t["reja"],1): parts.append(para("%d. %s"%(i,r),size=28,align="left",indent_first=360,space_after=40))
    parts.append(empty_para())
    for idx,(head,paras) in enumerate(t["sections"],1):
        parts.append(para("%d. %s"%(idx,head),bold=True,size=28,align="left",indent_first=0,space_after=80,keep_next=True))
        for p in paras: parts.append(para(p,size=28,align="both",indent_first=709,space_after=120))
    return "".join(parts)
def build_document():
    body="".join(build_topic(t,i==0) for i,t in enumerate(TOPICS))
    sect='<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/><w:pgNumType w:start="1"/></w:sectPr>'
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:body>'+body+sect+'</w:body></w:document>'
CT='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>'
RE='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>'
DR='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>'
ST='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/><w:lang w:val="uz-Latn-UZ"/></w:rPr></w:rPrDefault><w:pPrDefault><w:pPr><w:spacing w:line="360" w:lineRule="auto"/></w:pPr></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style></w:styles>'
def cp():
    n=datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Falsafa</dc:title><dc:creator>Konspekt</dc:creator><dcterms:created xsi:type="dcterms:W3CDTF">%s</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">%s</dcterms:modified></cp:coreProperties>'%(n,n)
AP='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties"><Application>Konspekt</Application></Properties>'
def write_docx(path):
    with zipfile.ZipFile(path,"w",zipfile.ZIP_DEFLATED) as z:
        z.writestr("[Content_Types].xml",CT); z.writestr("_rels/.rels",RE)
        z.writestr("word/document.xml",build_document()); z.writestr("word/_rels/document.xml.rels",DR)
        z.writestr("word/styles.xml",ST); z.writestr("docProps/core.xml",cp()); z.writestr("docProps/app.xml",AP)
    print("OK:",path,"|",len(TOPICS),"mavzu")

TOPICS.append({"num":1,"title":"Falsafa fani haqida tushunchalar","reja":["Falsafa tushunchasi va uning kelib chiqishi.","Falsafaning predmeti va asosiy savollari.","Falsafaning bo'limlari va tarmoqlari.","Falsafaning jamiyatdagi o'rni va vazifalari."],"sections":[("Falsafa tushunchasi va uning kelib chiqishi",["Falsafa — bu olam, inson va jamiyat haqidagi eng umumiy tushunchalar va qonuniyatlarni o'rganadigan fan. So'zning o'zi qadimgi yunon tilidan olingan: 'philosophia' — 'philo' (sevish) va 'sophia' (donolik), ya'ni 'donolikni sevish' degan ma'noni anglatadi.","Falsafa tarixiy jihatdan eramizdan avvalgi VI-V asrlarda Qadimgi Yunoniston, Hindiston va Xitoyda deyarli bir vaqtda paydo bo'lgan. Sokrat, Aflotun, Aristotel kabi yunon faylasuflari, Konfutsiy va Lao Tszi (Xitoy), Buddha (Hindiston) — birinchi falsafiy maktablarning asoschilaridir.","Sharqda, jumladan O'rta Osiyoda falsafa Forobiy, Ibn Sino, Beruniy, Imom Buxoriy kabi buyuk allomalar tomonidan rivojlantirilgan. Ular Sharq falsafasiga muhim hissa qo'shgan va uni yangi cho'qqilarga ko'targan."]),("Falsafaning predmeti va asosiy savollari",["Falsafaning predmeti — olamning eng umumiy qonuniyatlari, inson va olam, inson va jamiyat o'rtasidagi munosabatlar. Falsafa boshqa fanlardan farqli ravishda alohida hodisalarni emas, balki butun borliqning umumiy xususiyatlarini o'rganadi.","Nemis faylasufi Immanuil Kant falsafaning to'rt asosiy savolini ajratib ko'rsatgan: 1) Men nimani bila olaman? (bilim nazariyasi), 2) Men nima qilishim kerak? (axloq), 3) Men nimaga umid qilishim mumkin? (din falsafasi), 4) Inson nima? (antropologiya). Bu savollar bugungi kunda ham dolzarb.","Falsafa abadiy savollar bilan shug'ullanadi: borliq nima, haqiqat nima, yaxshilik va yomonlik, hayot ma'nosi, o'lim, erkinlik, adolat. Bu savollarga to'liq javob topish qiyin, lekin ularni o'rganish insonni chuqur fikr yuritishga, dunyoni tushunishga va ma'naviy rivojlanishga undaydi."]),("Falsafaning bo'limlari va tarmoqlari",["Falsafa bir nechta asosiy bo'limga bo'linadi: ontologiya (borliq haqidagi ta'limot), gnoseologiya yoki epistemologiya (bilim nazariyasi), aksiologiya (qadriyatlar haqidagi ta'limot), etika (axloq falsafasi), estetika (san'at va go'zallik falsafasi) va mantiq (to'g'ri fikr yuritish ilmi).","Falsafaning amaliy tarmoqlari: ijtimoiy falsafa (jamiyat haqida), siyosiy falsafa (davlat va hokimiyat), huquq falsafasi, din falsafasi, fan falsafasi, til falsafasi va inson falsafasi (antropologiya). Har bir tarmoq o'z mavzu doirasiga ega.","Zamonaviy falsafada yangi tarmoqlar ham paydo bo'lmoqda: ekologik falsafa, biotsenoz axloqi, axborot falsafasi, sun'iy intellekt falsafasi va boshqalar. Bu falsafaning hayotning yangi sohalariga moslashishini ko'rsatadi."]),("Falsafaning jamiyatdagi o'rni va vazifalari",["Falsafaning asosiy vazifalari: dunyoqarashni shakllantirish (insonga olamni tushunish va o'z o'rnini topish imkonini beradi), gnoseologik vazifa (bilish jarayonlarini o'rganish), metodologik vazifa (boshqa fanlar uchun umumiy usullar berish) va aksiologik vazifa (qadriyatlarni baholash).","Falsafa insonni tanqidiy fikrlashga, mustaqil mulohaza yuritishga, hodisalarning chuqur sabablarini izlashga va asoslangan qarorlar qabul qilishga o'rgatadi. Bu ko'nikmalar hayotning barcha sohalarida zarurdir.","Zamonaviy jamiyatda falsafa ayniqsa muhim: globallashuv, texnologik inqilob, ekologik muammolar va axloqiy dilemmalar yangi savollarni keltirib chiqaradi. Falsafa bu savollarga javob izlashda, jamiyat rivojlanishini to'g'ri yo'naltirishda muhim rol o'ynaydi."])],})

TOPICS.append({"num":2,"title":"Falsafa: Bilim nazariyasi va dunyoqarash","reja":["Bilim nazariyasi (gnoseologiya) tushunchasi.","Bilishning bosqichlari: hissiy va mantiqiy bilish.","Haqiqat tushunchasi va uning mezonlari.","Dunyoqarash va uning turlari."],"sections":[("Bilim nazariyasi (gnoseologiya) tushunchasi",["Gnoseologiya yoki epistemologiya — bilim haqidagi falsafiy ta'limot. U bilimning manbalari, chegaralari, ishonchliligi va haqiqatga erishish yo'llarini o'rganadi. Yunoncha 'gnosis' — bilim, 'logos' — ta'limot ma'nosini bildiradi.","Bilim nazariyasining asosiy savollari: bilim qanday paydo bo'ladi, biz qanday biladigan narsalarni bilamiz, haqiqat nima, bilimni qanday sinab ko'ramiz va bilimning chegaralari bormi? Bu savollarga turli faylasuflar har xil javoblar bergan.","Gnoseologiyada ikki asosiy yo'nalish bor: empirizm (bilim tajribadan kelib chiqadi — Bekon, Lokk, Yum) va ratsionalizm (bilim aql orqali olinadi — Dekart, Spinoza, Leybnits). Kant esa bu ikki yo'nalishni birlashtirishga harakat qilgan."]),("Bilishning bosqichlari: hissiy va mantiqiy bilish",["Bilish jarayoni ikki asosiy bosqichdan iborat: hissiy bilish (sezish, idrok, tasavvur) va mantiqiy bilish (tushuncha, hukm, xulosa). Hissiy bilish sezgi a'zolari orqali, mantiqiy bilish esa aql orqali amalga oshadi.","Hissiy bilish shakllari: sezgi (alohida xususiyatni aks ettirish — rang, tovush, ta'm), idrok (predmetni yaxlit aks ettirish), tasavvur (ko'rilgan narsani xotirada qayta tiklash). Bu bosqich bizga olamning to'g'ridan-to'g'ri ma'lumotini beradi.","Mantiqiy bilish shakllari: tushuncha (predmetlarning umumiy va muhim belgilarini aks ettirish), hukm (tushunchalar o'rtasidagi munosabatni ifodalash), xulosa (mavjud hukmlardan yangi hukm chiqarish). Bu bosqich abstrakt fikrlashni talab qiladi."]),("Haqiqat tushunchasi va uning mezonlari",["Haqiqat — bilimning obyektga muvofiqligi, ya'ni voqelikning ongda to'g'ri aks etishi. Haqiqat obyektivdir — uning mazmuni inson xohish-istagiga bog'liq emas. Masalan, 'Yer Quyosh atrofida aylanadi' degan fikr har qanday holatda ham haqiqatdir.","Haqiqat turlari: absolyut haqiqat (to'liq, mukammal va o'zgarmas bilim — bunga erishish qiyin) va nisbiy haqiqat (mavjud bilim darajasiga muvofiq, keyinchalik aniqlanishi mumkin). Fan rivojlanishi nisbiy haqiqatlardan absolyut haqiqatga yaqinlashish jarayonidir.","Haqiqat mezonlari: amaliyot (tajriba va eksperiment — eng asosiy mezon), mantiqiy izchillik (ichki ziddiyatsizlik), umumiy qabul qilinganlik (fan jamoatchiligi tomonidan tan olinishi), foydalilik (pragmatik mezon). Marksizmda asosiy mezon — amaliyot."]),("Dunyoqarash va uning turlari",["Dunyoqarash — insonning olam, jamiyat va o'zi haqidagi qarashlari, qadriyatlari va e'tiqodlari tizimidir. U inson xulq-atvori, qarorlari va hayot yo'lini belgilab beradi. Har bir inson o'z dunyoqarashiga ega.","Dunyoqarashning tarixiy turlari: mifologik dunyoqarash (qadimgi davr, afsonalar va xudolarga ishonish), diniy dunyoqarash (ilohiy kuchga e'tiqod), falsafiy dunyoqarash (aql va dalillarga asoslangan), ilmiy dunyoqarash (fan yutuqlariga tayanish). Ular tarixiy ketma-ketlikda rivojlangan.","Dunyoqarashning komponentlari: bilimlar (olam haqidagi ma'lumot), qadriyatlar (nima yaxshi va yomon), ishonch (e'tiqodlar), ideallar (intilish maqsadlari) va xulq-atvor tamoyillari. Salomat dunyoqarash insonning hayotda muvaffaqiyatli bo'lishiga asos."])],})

TOPICS.append({"num":3,"title":"Falsafa: Etika, axloq belgilari","reja":["Etika fani va uning predmeti.","Axloq tushunchasi va uning mohiyati.","Axloqning asosiy kategoriyalari.","Axloqiy tamoyillar va zamonaviy axloqiy muammolar."],"sections":[("Etika fani va uning predmeti",["Etika — axloq haqidagi falsafiy ta'limot. So'zning o'zi qadimgi yunoncha 'ethos' — 'odat, xulq-atvor' so'zidan kelib chiqqan. Etika atamasini birinchi marta Aristotel ilmiy muomalaga kiritgan va uni alohida fan sifatida ajratib ko'rsatgan.","Etikaning predmeti — yaxshilik va yomonlik, adolat va beadolat, vijdon, mas'uliyat, burch, sha'n va qadr-qimmat kabi axloqiy kategoriyalar. U insonning xulq-atvorini baholash va to'g'ri yo'l ko'rsatish bilan shug'ullanadi.","Etikaning bo'limlari: meta-etika (axloqiy mulohaza tabiati), normativ etika (qanday yashash kerak — qoidalar), amaliy etika (aniq vaziyatlarda axloqiy yechim — biotetika, biznes etikasi). Bu bo'limlar bir-birini to'ldiradi va birgalikda axloq nazariyasini tashkil etadi."]),("Axloq tushunchasi va uning mohiyati",["Axloq — odamlar o'rtasidagi munosabatlarni tartibga soluvchi, ijtimoiy fikr va ichki ishonchga asoslangan qoidalar va normalar tizimi. Axloq qonunlardan farqli ravishda majburiy emas, balki vijdoniy — odamning o'zi tomonidan qabul qilingan.","Axloqning xususiyatlari: universal xarakterga ega (hamma uchun amal qiladi), barqaror (asosiy normalar uzoq vaqt davomida o'zgarmaydi), ijtimoiy (jamoaviy hayotda shakllanadi) va shaxsiy (har bir inson o'zi qabul qiladi). Axloq jamiyatning ma'naviy holatini aks ettiradi.","Axloq va huquqning farqi: huquq — davlat tomonidan o'rnatiladi va majburlash bilan ta'minlanadi; axloq — jamiyat tomonidan shakllanadi va ichki ishonch hamda jamoatchilik fikri orqali amal qiladi. Lekin ular bir-biri bilan chambarchas bog'liq — ko'p qonunlar axloqiy normalarga asoslangan."]),("Axloqning asosiy kategoriyalari",["Yaxshilik va yomonlik — axloqning eng asosiy kategoriyalari. Yaxshilik — odamlar va jamiyatga foyda keltiradigan, ma'naviy yuksaltiruvchi narsa; yomonlik — ziyon yetkazadigan, ma'naviy tushiruvchi narsa. Bu tushunchalar nisbatan tushuniladi va madaniyatga bog'liq.","Adolat va beadolat — har kimga loyiq narsasini berish tamoyili. Adolat huquqiy (qonun oldida tenglik), ijtimoiy (resurslarning to'g'ri taqsimlanishi) va ma'naviy (xizmatga yarasha mukofot) bo'lishi mumkin. Beadolat — bu tamoyilning buzilishi.","Vijdon — insonning ichki axloqiy nazoratchisi, o'z xatti-harakatlarini baholovchi ovoz. Burch — insonning jamiyat va boshqalar oldidagi majburiyatlari. Sha'n va qadr-qimmat — insonning jamiyat va o'zi tomonidan baholanishi. Bu kategoriyalar inson axloqiy hayotining negizini tashkil etadi."]),("Axloqiy tamoyillar va zamonaviy axloqiy muammolar",["Asosiy axloqiy tamoyillar: 'Boshqalarga o'zingga qilishlarini istaganingdek qil' (oltin qoida — barcha dinlarda mavjud), insonga vosita sifatida emas, balki maqsad sifatida munosabatda bo'l (Kantning kategorik imperativi), eng ko'p odamlar uchun eng yaxshi natija (utilitarizm).","Zamonaviy biotsetnikadagi muammolar: evtanaziya (rahmdillik o'limi), abort, klonlash, organ transplantatsiyasi, genetik muhandislik. Bu masalalarda an'anaviy axloq yangi savollarga duch keladi va yangi qarorlar talab qiladi.","Boshqa zamonaviy muammolar: ekologik etika (tabiatga munosabat), AI etikasi (sun'iy intellekt huquqlari va mas'uliyati), raqamli etika (internet, maxfiylik), biznes etikasi (korporativ ijtimoiy mas'uliyat). Bu masalalar zamonaviy faylasuflar uchun asosiy tadqiqot mavzularidir."])],})

TOPICS.append({"num":4,"title":"Falsafa: Estetika, san'at falsafasi","reja":["Estetika tushunchasi va uning predmeti.","Estetik kategoriyalar: go'zallik, ulug'vorlik va boshqalar.","San'at falsafasi va uning vazifalari.","San'at turlari va ularning tasnifi."],"sections":[("Estetika tushunchasi va uning predmeti",["Estetika — go'zallik va san'at haqidagi falsafiy ta'limot. So'z qadimgi yunoncha 'aisthetikos' — 'his qiluvchi, sezuvchi' degan ma'noni bildiradi. Atamani 1735-yilda nemis faylasufi Aleksandr Baumgarten kiritgan va uni alohida fan sifatida ajratgan.","Estetikaning predmeti — go'zallik tabiati, badiiy ijod jarayoni, san'atning jamiyatdagi roli, badiiy idrok va estetik tarbiya. U faqat san'atni emas, balki tabiatdagi, ijtimoiy hayotdagi va kundalik turmushdagi go'zallikni ham o'rganadi.","Estetika boshqa fanlar bilan chambarchas bog'liq: san'atshunoslik (alohida san'at turlarini o'rganadi), psixologiya (badiiy idrok), sotsiologiya (san'at va jamiyat) va madaniyatshunoslik. Estetika bu fanlarni umumiy nazariy asos bilan ta'minlaydi."]),("Estetik kategoriyalar: go'zallik, ulug'vorlik va boshqalar",["Go'zallik — estetikaning markaziy kategoriyasi. Bu shakl, mazmun va g'oyaning uyg'unligidir. Go'zallikning meyorlari madaniyat va davrga qarab o'zgaradi, lekin asosiy xususiyatlari — uyg'unlik, mutanosiblik, izchillik — barcha madaniyatlarda umumiy.","Ulug'vorlik (sublime) — kishini hayratga soluvchi, qudrati va kattaligi bilan ta'sir qiluvchi narsa. Tog' cho'qqilari, dengiz to'lqinlari, kosmos manzaralari ulug'vorlik misollari. Ulug'vorlik bizda ham hayrat, ham qo'rquv aralash hissiyotlar uyg'otadi.","Boshqa estetik kategoriyalar: tragiklik (insonning kuch-qudrati ojiz qolgan jiddiy ziddiyat — Shekspirning 'Hamlet'i), komiklik (kulgili — kichik ziddiyat orqali kulgi keltirib chiqarish), behunarlik (xunuk — go'zallikning teskarisi), poetik (she'riy ruh)."]),("San'at falsafasi va uning vazifalari",["San'at — voqelikni badiiy obrazlar orqali aks ettirish va o'zgartirish faoliyati. San'at fan kabi haqiqatni izlaydi, lekin uni mantiqiy formulalar emas, balki his-tuyg'u va obrazlar tilida ifodalaydi. San'at insonning hissiy va ma'naviy boyligini namoyon etadi.","San'atning vazifalari: estetik (go'zallik va lazzat berish), bilish (voqelikni anglash), tarbiyaviy (axloqiy ta'sir), kommunikativ (insonlarni bog'lash), katarsis (his-tuyg'ulardan tozalanish — Aristotel), ko'ngilochar (dam olish va zavq).","San'at va voqelik munosabati — falsafiy bahslar mavzusi: realizm (san'at hayotni aniq aks ettiradi), romantizm (san'at ideal va xayoliy), modernizm (san'at avtonom — o'z qonunlariga ega), postmodernizm (san'at — o'yin va sitata). Har bir yondashuv san'atning bir tomonini ochib beradi."]),("San'at turlari va ularning tasnifi",["San'at turlari: ifodali san'atlar (musiqa, raqs, badiiy adabiyot — vaqtga bog'liq), tasviriy san'atlar (rangtasvir, haykaltaroshlik, arxitektura — fazoga bog'liq) va sintetik san'atlar (teatr, kino — vaqt va fazoni birlashtiradi).","Adabiyot — so'z san'ati, eng keng tarqalgan va ta'sirli san'at turi. Janrlari: epik (roman, qissa), lirik (she'r), dramatik (drama, komediya). O'zbek adabiyotida Navoiy, Bobur, Cho'lpon, Oybek, Abdulla Qodiriy kabi ulkan ijodkorlar bor.","Zamonaviy san'at turlari: kino (XX asrda paydo bo'lgan), fotografiya, dizayn, televideniye, raqamli san'at, video-art. Texnologiya rivoji yangi san'at shakllarini keltirib chiqarmoqda. Sun'iy intellekt yaratayotgan san'at — yangi falsafiy savol: bu san'atmi?"])],})

TOPICS.append({"num":5,"title":"Falsafa: Mantiq va argumentatsiya","reja":["Mantiq fani va uning vazifalari.","Mantiqning asosiy shakllari: tushuncha, hukm, xulosa.","Argumentatsiya va dalillash usullari.","Mantiqiy xatolar va ularni oldini olish."],"sections":[("Mantiq fani va uning vazifalari",["Mantiq — to'g'ri fikr yuritish qonunlarini o'rganadigan fan. So'z qadimgi yunoncha 'logos' — 'so'z, fikr, ta'limot' degan ma'noni bildiradi. Mantiqning asoschisi Aristotel hisoblanadi — uning 'Organon' asari mantiq tarixidagi birinchi tizimli ish.","Mantiqning vazifalari: to'g'ri fikr yuritish qonunlarini ochish, mantiqiy xatolarni aniqlash, dalillarni baholash va xulosalar chiqarish usullarini o'rgatish. Mantiq fan emas, balki barcha fanlar uchun zaruriy vositadir.","Sharqda mantiq fani Forobiy va Ibn Sino tomonidan rivojlantirilgan. Forobiyning 'Mantiq haqida' asari, Ibn Sinoning 'Kitob ash-shifo' asaridagi mantiq bo'limi bu sohaning rivojiga katta hissa qo'shgan. Mantiq O'rta asr Sharq universitetlarida asosiy o'quv fanlaridan biri bo'lgan."]),("Mantiqning asosiy shakllari: tushuncha, hukm, xulosa",["Tushuncha — predmetlarning umumiy va muhim belgilarini aks ettiruvchi fikr shakli. Tushuncha hajmi (qancha predmetni qamrab oladi) va mazmuni (qanday belgilarni o'z ichiga oladi) bilan tavsiflanadi. Masalan, 'inson' tushunchasi keng hajmga ega, 'professor' esa torroq.","Hukm — biror narsani tasdiqlash yoki rad etish shakli. U gap orqali ifodalanadi va albatta chin yoki yolg'on bo'ladi. Hukm tarkibi: subyekt (S — nima haqida gapirilmoqda), predikat (P — nima aytilmoqda), bog'lovchi va miqdor. Misol: 'Barcha odamlar (S) o'lim oldida tengdir (P)'.","Xulosa — bir yoki bir nechta hukmdan yangi hukm chiqarish jarayoni. Asosiy turlari: deduktiv (umumiydan xususiyga — sillogizm), induktiv (xususiydan umumiyga), analogik (o'xshash holatlarga asoslangan). Aristotelning klassik sillogizmi: 'Barcha odamlar o'ladi. Sokrat — odam. Demak, Sokrat o'ladi'."]),("Argumentatsiya va dalillash usullari",["Argumentatsiya — biror tezisni dalillar yordamida asoslash jarayoni. Uning tarkibi: tezis (isbotlanishi kerak bo'lgan fikr), argumentlar (dalillar — faktlar, statistika, mutaxassis fikri, ilmiy qonunlar) va demonstratsiya (tezis bilan argumentlar orasidagi mantiqiy bog'lanish).",", Dalillash usullari: to'g'ridan-to'g'ri (tezisni argumentlar bilan asoslash) va bilvosita (qarama-qarshi tezisning yolg'onligini ko'rsatish — apagogik dalil). Yana — mantiqiy dalil (mulohaza), empirik dalil (tajriba), avtoritetga havola, analogiya bilan dalillash.","Munozara va polemika madaniyati: argumentlar shaxsiy hujumga emas, fikrga qaratilishi kerak; raqib pozitsiyasini to'g'ri tushunish; o'z fikringizni aniq bayon etish; dalillarga sodiq bo'lish; o'z xatongizni tan olishga tayyor bo'lish. Bu sivilizatsiyali muloqotning asosi."]),("Mantiqiy xatolar va ularni oldini olish",["Mantiqiy xatolar (logical fallacies) ikki turga bo'linadi: shakliy xatolar (xulosa qoidalarining buzilishi) va mazmuniy xatolar (asoslarning yolg'onligi yoki noto'g'ri talqin). Bu xatolarni aniqlay bilish — tanqidiy fikrlash ko'nikmasidir.","Eng keng tarqalgan xatolar: ad hominem (raqibga shaxsan hujum qilish), strawman (raqib fikrini buzib ko'rsatish), false dilemma (faqat ikki variant taklif qilish), slippery slope (kichik qadam baliq baliqqa olib boradi degan asossiz da'vo), appeal to authority (asossiz avtoritetga murojaat).","Xatolardan saqlanish usullari: o'z fikrlaringizni tanqidiy baholash, manbalarni tekshirish, dalillarni dalillar bilan taqqoslash, hissiyotga emas, mantiqqa tayanish va boshqa nuqtai nazarlarni tushunishga harakat qilish. Yaxshi mantiqiy mahorat — har qanday sohada muvaffaqiyat kalitidir."])],})

TOPICS.append({"num":6,"title":"Din va falsafa","reja":["Din va falsafa o'rtasidagi munosabat.","Dunyo dinlari va ularning falsafiy asoslari.","Din falsafasining asosiy muammolari.","O'zbekistonda din va dunyoviylik."],"sections":[("Din va falsafa o'rtasidagi munosabat",["Din va falsafa — ikki turli, lekin o'zaro bog'liq dunyoqarash shakllaridir. Ikkalasi ham olamning ma'nosi, inson hayoti va o'lim, axloq va adolat haqidagi savollarga javob izlaydi. Lekin ular bunga turlicha yondashadi: din e'tiqod va vahiyga, falsafa esa aql va dalillarga tayanadi.","Tarixiy jihatdan din va falsafaning munosabati murakkab kechgan. O'rta asrlarda falsafa 'ilohiyotning xizmatkori' deb hisoblangan (xususan Yevropada). Sharqda Forobiy, Ibn Sino, G'azzoliy din va falsafani uyg'unlashtirishga harakat qilgan.","Zamonaviy yondashuvlar: din va falsafa bir-birini to'ldiradigan sohalar, har birining o'z mavzu doirasi bor. Falsafa dinning ratsional asoslarini o'rganadi (din falsafasi), din esa falsafa qamrab olmagan ma'naviy-ruhiy ehtiyojlarni qondiradi. Bag'rikenglik va o'zaro hurmat — eng to'g'ri munosabatdir."]),("Dunyo dinlari va ularning falsafiy asoslari",["Jahon dinlari uch asosiy turga bo'linadi: monoteistik (bir Xudoga e'tiqod — Islom, Xristianlik, Iudaizm), politeistik (ko'p xudolarga — qadimgi yunon dini, hinduizm) va nontheistik (xudosiz din — buddizm). Har birining o'ziga xos falsafiy ta'limoti bor.","Islom falsafasi: Allohning birligi (tavhid), payg'ambarlik, oxirat, taqdir va adolat tushunchalari asosida quriladi. Forobiy, Ibn Sino, G'azzoliy, Ibn Rushd kabi musulmon faylasuflari islom dunyoqarashini chuqur asoslab, dunyo falsafasiga katta hissa qo'shganlar.","Buddizm va hinduizm falsafiy ta'limotlari: karma (xatti-harakat va uning oqibati), reinkarnatsiya (ruhning qayta tug'ilishi), nirvana (azob-uqubatdan ozod bo'lish) va dharma (axloqiy yo'l). Bu g'oyalar Sharq falsafasining muhim qismi bo'lib, butun dunyoga ta'sir ko'rsatgan."]),("Din falsafasining asosiy muammolari",["Xudoning bor yoki yo'qligi muammosi falsafiy bahslarning markazida turadi. Tomas Akvinskiy va boshqalar Xudoning borligini dalillash uchun beshta dalil keltirgan: harakat, sabab, ehtimollik, mukammallik va maqsadlilik. Tanqidchilar (Yum, Kant) bu dalillarni shubha ostiga olganlar.","Yomonlik muammosi (theodicy): agar Xudo qudratli, donishmand va mehribon bo'lsa, nega olamda yomonlik bor? Bu savolga turli javoblar berilgan: yomonlik insonning erkin tanlovidan kelib chiqadi, yomonlik yaxshilikni anglash uchun zarur, yomonlik — sinov.","Boshqa muhim masalalar: e'tiqod va aql munosabati, mo'jizalar tabiati, jonning o'lmasligi, oxirat va jannat-do'zax tushunchalari, vahiy va ilohiy bilim. Bu masalalar diniy mutafakkirlar va faylasuflar tomonidan asrlar davomida muhokama qilib kelinmoqda."]),("O'zbekistonda din va dunyoviylik",["O'zbekiston Konstitutsiyasiga ko'ra dunyoviy davlat: din davlatdan ajratilgan, lekin diniy erkinlik kafolatlangan. Fuqarolar istalgan diniy e'tiqodda bo'lish yoki bo'lmaslik huquqiga ega. Davlat hech bir dinni boshqasidan ustun qo'ymaydi.","Mamlakatda asosan musulmonlar yashaydi (taxminan 90%), shuningdek nasroniylar (pravoslav, katolik, protestant), iudaylar va boshqa diniy guruhlar ham bor. Ular o'rtasida totuvlik va o'zaro hurmat saqlanadi — bu O'zbekistonning muhim yutug'i.","Yangilangan O'zbekistonda diniy bag'rikenglik kuchaytirildi: masjidlar, cherkovlar va ibodatxonalar erkin faoliyat yuritadi, diniy adabiyot nashr etiladi, diniy ta'lim muassasalari ishlaydi. Shu bilan birga, diniy ekstremizmga qarshi qat'iy turiladi va dinning siyosiylashishiga yo'l qo'yilmaydi."])],})

TOPICS.append({"num":7,"title":"Ijtimoiy falsafa","reja":["Ijtimoiy falsafa tushunchasi va predmeti.","Jamiyat va uning rivojlanish qonuniyatlari.","Ijtimoiy strukturalar va munosabatlar.","Adolat va siyosiy falsafa."],"sections":[("Ijtimoiy falsafa tushunchasi va predmeti",["Ijtimoiy falsafa — jamiyat haqidagi falsafiy ta'limot. U jamiyatning paydo bo'lishi, tuzilishi, rivojlanish qonuniyatlari va inson va jamiyat o'rtasidagi munosabatlarni o'rganadi. Bu sohaga siyosiy falsafa, huquq falsafasi va tarix falsafasi ham yaqindir.","Ijtimoiy falsafaning asosiy savollari: Jamiyat nima va u qanday paydo bo'ldi? Jamiyat rivojining harakatlantiruvchi kuchlari nimalar? Adolat nima va uni qanday ta'minlash mumkin? Davlat va jamiyat munosabatlari qanday bo'lishi kerak? Inson va jamoa qaysi ustunlikka ega?","Klassik ijtimoiy faylasuflar: Aflotun ('Davlat'), Aristotel ('Siyosat'), Tomas Mor ('Utopiya'), Tomas Hobbs ('Leviafan'), Jon Lokk, Russo, Marks, Vebber, Xabermas. Sharqda — Forobiy ('Fozil odamlar shahri'), Ibn Xaldun ('Muqaddima')."]),("Jamiyat va uning rivojlanish qonuniyatlari",["Jamiyat — bir hududda yashovchi, umumiy madaniyat, til va tarixga ega bo'lgan, o'zaro munosabatda bo'ladigan odamlar uyushmasi. U faqat odamlar yig'indisi emas, balki murakkab tizim — o'z qonuniyatlari bilan ishlaydi. Jamiyatda iqtisodiy, siyosiy, ijtimoiy va madaniy qism tizimlar mavjud.","Jamiyat rivojlanish nazariyalari: Marksning formatsion nazariyasi (jamiyat besh formatsiyadan o'tadi: ibtidoiy, qulchilik, feodalizm, kapitalizm, kommunizm), Toynbi va Spenglerning sivilizatsion yondashuvi (mustaqil sivilizatsiyalar), zamonaviy modernizatsiya nazariyasi.","Jamiyat rivojini harakatlantiruvchi kuchlar: ishlab chiqaruvchi kuchlar va ishlab chiqarish munosabatlari (Marks), elita va ommani (Pareto), g'oyalar va ma'naviyat (Vebber), texnologiya (Bell), informatsiya (Kastels). Har bir nazariya jamiyat rivojining muhim tomonini ochib beradi."]),("Ijtimoiy strukturalar va munosabatlar",["Ijtimoiy struktura — jamiyatning ichki tuzilishi: sinflar, ijtimoiy qatlamlar, milliy guruhlar, kasbiy guruhlar va ularning o'zaro munosabatlari. Bu struktura nisbatan barqaror bo'lib, jamiyatning tartibli ishlashini ta'minlaydi.","Ijtimoiy stratifikatsiya — jamiyatning vertikal qatlamlanishi: yuqori, o'rta va quyi sinflar. Stratifikatsiya mezonlari: daromad, mulk, kuch (vakolat), obro' (prestij), ta'lim. Zamonaviy demokratik jamiyatlarda o'rta sinfning kuchli bo'lishi muhim — bu barqarorlikni ta'minlaydi.","Ijtimoiy mobillik — odamlarning ijtimoiy strukturadagi vertikal harakati (yuqoriga ko'tarilish yoki tushish). U gorizontal (bir kasbdan boshqasiga) va vertikal bo'lishi mumkin. Ochiq jamiyatlarda mobillik yuqori, yopiqlarda past — qadimgi Hindiston kasta tizimi yopiq jamiyat misolidir."]),("Adolat va siyosiy falsafa",["Adolat — siyosiy falsafaning markaziy tushunchasi. Aflotunga ko'ra, har kim o'z ishi bilan shug'ullansa, jamiyatda adolat hukm suradi. Aristotel adolatni ikki turga bo'lgan: taqsimlovchi (resurslarning teng taqsimlanishi) va to'g'rilash (qonunbuzarlikni jazolash).","Zamonaviy adolat nazariyalari: Jon Rolzning 'Adolat nazariyasi' (1971) — eng nufuzlilaridan biri. U 'noma'lumlik pardasi' tajribasini taklif etadi: agar bilmasangiz qaysi pozitsiyada tug'ilasiz, qanday adolatli jamiyat tuzar edingiz? Bu test orqali eng adolatli printsiplar topiladi.","Siyosiy falsafadagi asosiy bahslar: liberalizm (individual erkinlik birinchi) vs kommunitarizm (jamoa muhim), erkinlik vs tenglik balansi, demokratiya turlari (vakillik, bevosita, deliberativ), davlatning roli (kichik vs katta hukumat). Bu masalalar zamonaviy siyosatning markaziy mavzularidir."])],})

TOPICS.append({"num":8,"title":"Ilm-fan va texnologiya falsafasi","reja":["Fan falsafasi va uning predmeti.","Ilmiy bilishning xususiyatlari va usullari.","Fan va texnologiya rivoji bosqichlari.","Texnologiya va inson hayoti."],"sections":[("Fan falsafasi va uning predmeti",["Fan falsafasi — fan haqidagi falsafiy ta'limot. U fanning tabiati, ilmiy bilishning usullari, ilmiy haqiqatning mezonlari, fan rivoji qonuniyatlari va fan jamiyatdagi roli kabi savollarni o'rganadi. Bu ko'p tomonlama soha — har bir fan turining o'z falsafasi bor.","Fan falsafasining asosiy savollari: fanning fan emasdan farqi nimada (demarkatsiya muammosi)? Ilmiy nazariya qanday qurib chiqiladi? Fan qanday taraqqiy etadi? Ilmiy haqiqat absolyutmi yoki nisbiy? Ilmiy bilim qanday tasdiqlanadi yoki rad etiladi?","Mashhur fan faylasuflari: Karl Popper (falsifikatsiya nazariyasi — ilmiy nazariya rad etilishi mumkin bo'lishi kerak), Tomas Kun ('Fanning paradigmal o'zgarishlari'), Imre Lakatos (ilmiy tadqiqot dasturlari), Pol Feyerabend (metodologik anarxizm). Ular fan falsafasiga muhim hissa qo'shganlar."]),("Ilmiy bilishning xususiyatlari va usullari",["Ilmiy bilimning xususiyatlari: obyektivlik (subyektiv his-tuyg'ulardan xoli), tizimlilik (uyushgan, mantiqiy bog'liq), empirik tasdiqlanganlik (tajriba bilan tekshirilgan), umumiyligi va zaruriyligi, takrorlanishi (bir xil sharoitda bir xil natija) va konsepsiyalanganligi (asosli nazariyaga ega).","Ilmiy bilish bosqichlari: empirik (tajribaga asoslangan — kuzatish, eksperiment, o'lchash) va nazariy (mavhum fikrlashga asoslangan — gipoteza, model, qonun, nazariya). Ikkala bosqich birgalikda ilmiy bilimni tashkil etadi.","Ilmiy bilish usullari: umumilmiy usullar (induksiya, deduksiya, analiz, sintez, modellashtirish, abstraksiya, formalizatsiya) va xususiy usullar (har bir fanda o'ziga xos). Tabiiy fanlar uchun eksperiment, ijtimoiy fanlar uchun so'rovnoma, gumanitar fanlar uchun matnni tahlil qilish xosdir."]),("Fan va texnologiya rivoji bosqichlari",["Fanning rivojlanish bosqichlari: klassik fan (XVII-XIX asrlar — Galileo, Nyuton, Darvin), neklassik fan (XX asr — Eynshteyn, kvant fizikasi — kuzatuvchining ta'siri tan olinadi) va postneklassik fan (XX asrning oxiri — kompleks tizimlar, sinergetika, qadriyatlar fanga kiritiladi).","Texnologik inqiloblar: 1-inqilob — neolit (qishloq xo'jaligi), 2-inqilob — sanoat (mashinalar, bug' dvigateli), 3-inqilob — ilmiy-texnik (XX asr o'rtasi — atom energiyasi, kompyuter), 4-inqilob — raqamli/axborot (XXI asr — internet, AI, biotexnologiya).","Zamonaviy texnologik tendensiyalar: sun'iy intellekt, kvant kompyuterlari, genetik muhandislik, nanotexnologiyalar, robototexnika, virtual va kengaytirilgan reallik. Bu texnologiyalar fan va falsafaga yangi savollar tug'diradi: AI ongli bo'la oladimi? Inson tabiatini o'zgartirish axloqiymi?"]),("Texnologiya va inson hayoti",["Texnologiya inson hayotini tubdan o'zgartirgan: kommunikatsiya (smartfon, internet), transport (avtomobil, samolyot), tibbiyot (yangi davolash usullari), ta'lim (raqamli ta'lim), mehnat (avtomatlashtirish). Bu o'zgarishlar yangi imkoniyatlar va yangi muammolarni keltirib chiqaradi.","Texnologiyaning ijobiy va salbiy tomonlari: ijobiy — hayot oson va qulayroq, kasallikdan qutulish, ma'lumotga oson kirish, masofalarni qisqartirish; salbiy — texnogen falokatlar, ekologik muammolar, ishsizlik (avtomatlashtirish tufayli), shaxsiy hayot maxfiyligining yo'qolishi, raqamli qaramlik.","Texnologiya falsafasining muammolari: texnologiyani inson nazoratidan chiqib ketishi xavfi, transgumanizm (insonni texnologiya bilan kuchaytirish), genetik muhandislikning axloqiy chegaralari, raqamli tengsizlik. Bu masalalar texnologiyani insonparvarona yo'naltirish zaruriyatini ko'rsatadi."])],})

TOPICS.append({"num":9,"title":"Zamonaviy falsafa","reja":["Zamonaviy falsafaning asosiy yo'nalishlari.","Ekzistensializm va fenomenologiya.","Postmodernizm va analitik falsafa.","Zamonaviy falsafiy muammolar va savollar."],"sections":[("Zamonaviy falsafaning asosiy yo'nalishlari",["Zamonaviy falsafa — XX-XXI asr falsafasi bo'lib, klassik falsafadan jiddiy farq qiladi. U inson, jamiyat, til, ong, texnologiya kabi mavzularga yangicha yondashadi. Bu davrda dunyo urushlari, totalitar rejimlar, ilmiy-texnik inqilob va globalizatsiya falsafiy fikrga katta ta'sir ko'rsatdi.","Zamonaviy falsafaning asosiy yo'nalishlari: ekzistensializm, fenomenologiya, germenevtika, strukturalizm va poststrukturalizm, postmodernizm, analitik falsafa, fan falsafasi, neopragmatizm, feministik falsafa va ekofalsafa. Har biri o'ziga xos savollar va usullar bilan ajralib turadi.","Zamonaviy falsafa ko'p sohaga bo'lingan, lekin umumiy tendensiyalari bor: tanqidiy yondashuv, klassik metafizikadan qochish, til va ma'noga e'tibor, kontekstuallik, plyuralizm. Falsafa endi yagona haqiqat izlamaydi, balki turli pozitsiyalar dialogini qadrlaydi."]),("Ekzistensializm va fenomenologiya",["Ekzistensializm — XX asr boshida paydo bo'lgan, inson borligi (ekzistensiya) muammosini markazga qo'ygan falsafa. Asoschilari: Soren Kerkegor (XIX asr — kashshof), Karl Yaspers, Martin Xaydegger, Jan-Pol Sartr, Albert Kamyu, Gabriel Marsel, Symona de Bovuar.","Ekzistensializmning asosiy g'oyalari: 'borliq mohiyatdan oldin keladi' (Sartr — odam avval mavjud bo'ladi, keyin o'zini yaratadi), erkin tanlov va mas'uliyat, hayotning absurdligi (Kamyu), o'lim oldida tushunish (Xaydegger), avtentik (haqiqiy) hayot izlash. Bu falsafa odamga o'z hayoti uchun mas'uliyatni yuklaydi.","Fenomenologiya — Edmund Gusserlning ta'limoti. Uning shiori: 'Narsalarning o'zlariga qaytaylik!' Fenomenologiya ongning to'g'ridan-to'g'ri tajribasini o'rganadi, oldindan tayyor nazariyalardan qochadi. Bu yondashuv keyinchalik psixologiya, sotsiologiya va ilm-fanga ta'sir ko'rsatdi."]),("Postmodernizm va analitik falsafa",["Postmodernizm — XX asrning ikkinchi yarmida shakllangan, klassik falsafiy va madaniy g'oyalarni tanqid qiladigan harakat. Asosiy vakillar: Jan-Fransua Liotar, Mishel Fuko, Jak Derrida, Jan Bodriyar, Richard Rorti. Ular 'katta hikoyalar'ga (yagona haqiqat, taraqqiyot mafkurasi) shubha bilan qaraydilar.","Postmodernizm xususiyatlari: plyuralizm (ko'p haqiqatlar), dekonstruksiya (matn ma'nolarini ochib tashlash), hokimiyat va bilim aloqasi (Fuko), simulakr (haqiqatdan ajratilgan obrazlar — Bodriyar), katta hikoyalarga ishonchsizlik. Postmodernizm madaniyat va san'atga ham katta ta'sir ko'rsatgan.","Analitik falsafa — asosan ingliz tilida so'zlashuvchi mamlakatlarda rivojlangan yo'nalish. U til tahliliga, mantiqqa va aniq formulirovkaga e'tibor qaratadi. Vakillar: Bertran Rassel, Lyudvig Vitgenshteyn, Vilard Kvayn, Jon Sirl. Ular falsafa muammolarining ko'pi til xatolaridan kelib chiqadi deb hisoblaydilar."]),("Zamonaviy falsafiy muammolar va savollar",["Globalizatsiya muammolari: madaniyatlarning o'zaro ta'siri va to'qnashuvi, milliy o'zlikni saqlash, iqtisodiy tengsizlik, transmilliy korporatsiyalar hokimiyati. Falsafa bu jarayonlarni tushunish va boshqarishga yordam berishi kerak.","Texnologik muammolar: sun'iy intellekt etikasi (AI ongli bo'la oladimi? AI mas'uliyatni o'z zimmasiga ololadimi?), genetik muhandislikning chegaralari, transgumanizm (insonni texnologik takomillashtirish), maxfiylik va kuzatuv jamiyati, raqamli identifikatsiya.","Ekologik va biotsenoz muammolar: iqlim o'zgarishi, biologik xilma-xillikning yo'qolishi, hayvonlar huquqlari, kelajak avlodlar oldidagi mas'uliyat. Zamonaviy falsafa bu masalalarda yangi axloq va dunyoqarash izlamoqda — antropotsentrizmdan ekotsentrizmga o'tish."])],})

TOPICS.append({"num":10,"title":"Global jarayonlarning shakllari","reja":["Globalizatsiya tushunchasi va uning mohiyati.","Iqtisodiy globalizatsiya.","Madaniy va axborot globalizatsiyasi.","Globalizatsiya muammolari va istiqbollari."],"sections":[("Globalizatsiya tushunchasi va uning mohiyati",["Globalizatsiya — dunyo mamlakatlari, xalqlari va madaniyatlari o'rtasidagi aloqalarning kuchayishi va o'zaro bog'liqlik darajasining oshishi jarayonidir. Bu jarayonda iqtisodiy, siyosiy, madaniy va axborot chegaralari quvilmoqda, dunyo bir-biriga yaqinlashmoqda.","Globalizatsiyaning sabablari: ilmiy-texnik inqilob (transport, kommunikatsiya), bozor iqtisodiyotining kengayishi, transmilliy korporatsiyalarning rivojlanishi, sovuq urushning tugashi, internet va raqamli texnologiyalar. Bu omillar dunyoni yagona maydonga aylantirdi.","Globalizatsiyaning shakllari: iqtisodiy (jahon savdosi, moliya bozorlari), siyosiy (xalqaro tashkilotlar, BMT), madaniy (san'at, sport, urf-odatlar almashinuvi), axborot (internet, OAV) va ekologik (atrof-muhit muammolari hammaga taalluqli). Har bir shakl o'ziga xos xususiyatlarga ega."]),("Iqtisodiy globalizatsiya",["Iqtisodiy globalizatsiya — milliy iqtisodiyotlarning yagona jahon iqtisodiy tizimiga birlashishi. Asosiy ko'rinishlari: jahon savdosining o'sishi, kapital harakatlanishi, transmilliy korporatsiyalar (TMK), xalqaro mehnat taqsimoti va moliyaviy bozorlarning integratsiyasi.","Jahon iqtisodiyotini boshqaruvchi institutlar: Jahon banki (kreditlar va loyihalar), Xalqaro valyuta fondi (moliyaviy barqarorlik), Jahon savdo tashkiloti — JST (savdo qoidalari), Iqtisodiy hamkorlik va taraqqiyot tashkiloti — OECD (rivojlangan davlatlar). Ular xalqaro iqtisodiy tartibni belgilaydi.","Iqtisodiy globalizatsiyaning ijobiy va salbiy tomonlari: ijobiy — iqtisodiy o'sish, yangi texnologiyalar tarqalishi, ish o'rinlari, mahsulotlarning arzonlashishi; salbiy — iqtisodiy beqarorlik (inqirozlar tez tarqaladi), milliy iqtisodiyotlar himoyasi qiyin, transmilliy korporatsiyalarning kuchayishi, mehnat huquqlarining buzilishi."]),("Madaniy va axborot globalizatsiyasi",["Madaniy globalizatsiya — turli madaniyatlarning o'zaro ta'siri, bir-biriga aralashishi va g'arbiy madaniyatning ustun ta'siri (madaniy gomogenlik tendensiyasi). Xolivud filmlari, mashhur musiqa, fast-food, brendlar — bu jarayonning ko'rinishlari.","Axborot globalizatsiyasi internet va raqamli texnologiyalar bilan bog'liq. Ma'lumot bir soniyada dunyoning narigi chetiga yetib boradi. Ijtimoiy tarmoqlar global muloqot platformasiga aylandi. Bu yangi imkoniyatlar — ta'lim, biznes, do'stlik — beradi, lekin yolg'on axborot va manipulyatsiya xavfini ham keltiradi.","Madaniy globalizatsiyaga reaksiya turlicha: ba'zilar uni qabul qiladi (kosmopolitizm), boshqalari o'z madaniyatini saqlash uchun kurashadi (millatchilik), uchinchilari uyg'unlikni izlaydi (multikulturalizm — ko'p madaniyatli jamiyat). O'zbekiston o'z milliy madaniyatini saqlab qolish bilan birga, jahon madaniyatining ijobiy yutuqlaridan foydalanishga intiladi."]),("Globalizatsiya muammolari va istiqbollari",["Globalizatsiya muammolari: rivojlangan va rivojlanayotgan mamlakatlar o'rtasidagi tengsizlikning ortishi, ekologik buzilish, milliy madaniyatlarning yo'q bo'lib ketishi, transmilliy jinoyatchilik (terrorizm, narkotik trafiki, kiber-jinoyatlar), mehnat migratsiyasi muammolari, infektsion kasalliklarning tez tarqalishi (COVID-19 misol).","Antiglobalizm va alterglobalizm harakatlari: globalizatsiyaning salbiy oqibatlariga qarshi ijtimoiy harakatlar. Ular kambag'al mamlakatlar manfaatlarini himoya qilish, ekologiyani saqlash, transmilliy korporatsiyalar hokimiyatini cheklash va adolatli savdoni rag'batlantirishga harakat qiladi.","Globalizatsiya istiqbollari: agar to'g'ri boshqarilsa, u dunyo muammolarini hal qilish (qashshoqlik, kasalliklar, ekologik inqirozlar) uchun katta imkoniyat. Buning uchun xalqaro hamkorlik kuchaytirilishi, BMT roli oshirilishi, adolatli iqtisodiy tartib o'rnatilishi va madaniy xilma-xillik saqlanishi kerak. Globalizatsiya — qaytmas jarayon, lekin uni insonparvar qilish — bizning vazifamiz."])],})

